class Solution {
    private static final int MOD = 1_000_000_007;

    public int numberOfStableArrays(int zero, int one, int limit) {
        int[][][] dp = new int[zero + 1][one + 1][2];
        int[][][] sum = new int[zero + 1][one + 1][2];

        for (int z = 1; z <= zero; z++) {
            if (z <= limit) {
                dp[z][0][0] = 1;
            }
            sum[z][0][0] = (sum[z - 1][0][0] + dp[z][0][0]) % MOD;
            sum[z][0][1] = 0;
        }

        for (int o = 1; o <= one; o++) {
            if (o <= limit) {
                dp[0][o][1] = 1;
            }
            sum[0][o][0] = 0;
            sum[0][o][1] = (sum[0][o - 1][1] + dp[0][o][1]) % MOD;
        }

        for (int z = 1; z <= zero; z++) {
            for (int o = 1; o <= one; o++) {
                int maxZ = Math.max(0, z - limit);
                int maxO = Math.max(0, o - limit);

                dp[z][o][0] = (sum[z - 1][o][1] - (maxZ > 0 ? sum[maxZ - 1][o][1] : 0) + MOD) % MOD;
                dp[z][o][1] = (sum[z][o - 1][0] - (maxO > 0 ? sum[z][maxO - 1][0] : 0) + MOD) % MOD;

                sum[z][o][0] = (sum[z - 1][o][0] + dp[z][o][0]) % MOD;
                sum[z][o][1] = (sum[z][o - 1][1] + dp[z][o][1]) % MOD;
            }
        }

        return (dp[zero][one][0] + dp[zero][one][1]) % MOD;
    }
}
